   179	  // 预先规划栈帧：给 SSA 值、alloca 对象、临时寄存器和保存现场留空间。
   180	  void computeFrameLayoutBase(const llvm::Function& f)
   181	  {
   182	    int32_t off = 0;
   183	
   184	    // Stack slots for SSA values (sp-relative, positive offsets).
   185	    for (const llvm::Argument& arg : f.args()) {
   186	      llvm::Register vreg = newVReg();
   187	      valueVReg_[&arg] = vreg;
   188	      vregSpill_[vreg] = off;
   189	      off += 8;
   190	    }
   191	
   192	    for (const llvm::BasicBlock& bb : f) {
   193	      for (const llvm::Instruction& inst : bb) {
   194	        if (inst.getType()->isVoidTy())
   195	          continue;
   196	        llvm::Register vreg = newVReg();
   197	        valueVReg_[&inst] = vreg;
   198	        vregSpill_[vreg] = off;
   199	        off += 8;
   200	      }
   201	    }
   202	
   203	    // Stack storage for allocas.
   204	    for (const llvm::BasicBlock& bb : f) {
   205	      for (const llvm::Instruction& inst : bb) {
   206	        const auto* ai = llvm::dyn_cast<llvm::AllocaInst>(&inst);
   207	        if (!ai)
   208	          continue;
   209	        llvm::Type* ty = ai->getAllocatedType();
   210	        if (!ai->isStaticAlloca())
   211	          llvm::report_fatal_error("dynamic alloca is not supported");
   212	        int64_t sz = dl_.getTypeAllocSize(ty);
   213	        int64_t cnt = 1;
   214	        if (const llvm::Value* arr = ai->getArraySize()) {
   215	          if (const auto* ci = llvm::dyn_cast<llvm::ConstantInt>(arr)) {
   216	            cnt = ci->getSExtValue();
   217	          } else {
   218	            llvm::report_fatal_error("non-constant alloca array size");
   219	          }
   220	        }
   221	        int64_t bytes = sz * cnt;
   222	        int64_t align = std::max<int64_t>(8, static_cast<int64_t>(ai->getAlign().value()));
   223	        off = static_cast<int32_t>((off + align - 1) & ~(align - 1));
   224	        allocaOff_[ai] = off;
   225	        off += static_cast<int32_t>(bytes);
   226	      }
   227	    }
   228	
   229	    // Temp vreg spill slots.
   230	    for (unsigned i = 0; i < tempSlots_; ++i) {
   231	      llvm::Register vreg = newVReg();
   232	      tempVRegs_.push_back(vreg);
   233	      vregSpill_[vreg] = off;
   234	      off += 8;
   235	    }
   236	
   237	    // Reserve space for saved ra/s0 and align to 16 bytes.
   238	    off += 16;
   239	    localBytes_ = static_cast<int32_t>((off + 15) & ~15);
   240	    saveRaOff_ = localBytes_ - 8;
   241	    saveS0Off_ = localBytes_ - 16;
   242	  }
