   253	  // 取一个临时虚拟寄存器，专门给中间计算或常量加载使用。
   254	  llvm::Register nextTempVReg()
   255	  {
   256	    if (tempVRegs_.empty())
   257	      llvm::report_fatal_error("temp vregs not initialized");
   258	    llvm::Register vreg = tempVRegs_[tempCursor_++ % tempVRegs_.size()];
   259	    return vreg;
   260	  }
