   295	  // 翻译 br，同时处理 PHI 需要的边上复制。
   296	  // 关键点是：真正的 PHI move 不放在前驱块末尾，而是放进单独的 edge block。
   297	  void emitBranchInst(const llvm::BranchInst& bi)
   298	  {
   299	    if (!curBB_)
   300	      llvm::report_fatal_error("missing current basic block");
   301	
   302	    if (bi.isUnconditional()) {
   303	      const llvm::BasicBlock* succ = bi.getSuccessor(0);
   304	      auto moves = collectPhiMoves(*curBB_, *succ);
   305	      std::string target = bbLabel(*succ);
   306	      if (!moves.empty()) {
   307	        std::string edgeLabel = makeEdgeLabel();
   308	        pendingEdges_.push_back(EdgeBlock{edgeLabel, target, std::move(moves)});
   309	        emitVBranchUncond(edgeLabel);
   310	      } else {
   311	        emitVBranchUncond(target);
   312	      }
   313	      return;
   314	    }
   315	
   316	    llvm::Register cond = emitLoadValue(bi.getCondition());
   317	    const llvm::BasicBlock* tbb = bi.getSuccessor(0);
   318	    const llvm::BasicBlock* fbb = bi.getSuccessor(1);
   319	
   320	    auto tMoves = collectPhiMoves(*curBB_, *tbb);
   321	    auto fMoves = collectPhiMoves(*curBB_, *fbb);
   322	
   323	    std::string tLabel = tMoves.empty() ? bbLabel(*tbb) : makeEdgeLabel();
   324	    std::string fLabel = fMoves.empty() ? bbLabel(*fbb) : makeEdgeLabel();
   325	
   326	    if (!tMoves.empty())
   327	      pendingEdges_.push_back(EdgeBlock{tLabel, bbLabel(*tbb), std::move(tMoves)});
   328	    if (!fMoves.empty())
   329	      pendingEdges_.push_back(EdgeBlock{fLabel, bbLabel(*fbb), std::move(fMoves)});
   330	
   331	    emitVBranchCond(cond, tLabel, false);
   332	    emitVBranchUncond(fLabel);
   333	  }
