   335	  // 翻译 switch：逐个 case 比较，相等就跳走，最后落到 default。
   336	  // 它和条件分支一样，也要照顾目标块里的 PHI 赋值。
   337	  void emitSwitchInst(const llvm::SwitchInst& si)
   338	  {
   339	    if (!curBB_)
   340	      llvm::report_fatal_error("missing current basic block");
   341	
   342	    llvm::Register val = emitLoadValue(si.getCondition());
   343	    for (const auto& c : si.cases()) {
   344	      int64_t imm = c.getCaseValue()->getSExtValue();
   345	      llvm::Register caseReg = nextTempVReg();
   346	      emitVLoadImm(caseReg, imm);
   347	      llvm::Register tmp = nextTempVReg();
   348	      emitVXor(tmp, val, caseReg);
   349	      llvm::Register iseq = nextTempVReg();
   350	      emitVSltiu(iseq, tmp, 1);
   351	
   352	      const llvm::BasicBlock* succ = c.getCaseSuccessor();
   353	      auto moves = collectPhiMoves(*curBB_, *succ);
   354	      std::string label = moves.empty() ? bbLabel(*succ) : makeEdgeLabel();
   355	      if (!moves.empty())
   356	        pendingEdges_.push_back(EdgeBlock{label, bbLabel(*succ), std::move(moves)});
   357	      emitVBranchCond(iseq, label, false);
   358	    }
   359	
   360	    const llvm::BasicBlock* def = si.getDefaultDest();
   361	    auto defMoves = collectPhiMoves(*curBB_, *def);
   362	    std::string defLabel = defMoves.empty() ? bbLabel(*def) : makeEdgeLabel();
   363	    if (!defMoves.empty())
   364	      pendingEdges_.push_back(EdgeBlock{defLabel, bbLabel(*def), std::move(defMoves)});
   365	    emitVBranchUncond(defLabel);
   366	  }
