   368	  // 收集从 pred 进入 succ 时需要执行的 PHI move。
   369	  // 这一步只“记下来”，真正发指令在 emitPhiMoves 里完成。
   370	  llvm::SmallVector<PhiMove, 4> collectPhiMoves(const llvm::BasicBlock& pred,
   371	                                                const llvm::BasicBlock& succ) const
   372	  {
   373	    llvm::SmallVector<PhiMove, 4> moves;
   374	    for (const llvm::Instruction& inst : succ) {
   375	      const auto* phi = llvm::dyn_cast<llvm::PHINode>(&inst);
   376	      if (!phi)
   377	        break;
   378	      const llvm::Value* incoming = phi->getIncomingValueForBlock(&pred);
   379	      if (!incoming)
   380	        llvm::report_fatal_error("missing phi incoming value");
   381	      moves.push_back(PhiMove{vregOf(phi), incoming});
   382	    }
   383	    return moves;
   384	  }
