   386	  // 把一组 PHI move 展开成普通寄存器复制。
   387	  void emitPhiMoves(const llvm::SmallVectorImpl<PhiMove>& moves)
   388	  {
   389	    for (const PhiMove& mv : moves) {
   390	      llvm::Register src = emitLoadValue(mv.src);
   391	      if (src == mv.dst)
   392	        continue;
   393	      emitVMov(mv.dst, src);
   394	    }
   395	  }
